#![allow\(dead_code\)]

use std::cell::RefCell;
use js_sys::{Array, Reflect};
use wasm_bindgen::{JsCast, JsValue};
use wasm_bindgen::closure::Closure;

use crate::dom;
use crate::storage;

thread_local! {
  static TTS_STATE: RefCell<TtsState> = RefCell::new\(TtsState::default\(\)\);
}

#[derive\(Clone, Debug\)]
struct TtsState {
  enabled: bool,
  voice_uri: Option<String>,
  rate: f32,
  pitch: f32,
}

impl Default for TtsState {
  fn default\(\) -> Self {
    TtsState {
      enabled: storage::local_get\("tts-enabled"\)
        .and_then\(|s| s.parse::<bool>\(\).ok\(\)\)
        .unwrap_or\(true\),
      voice_uri: storage::local_get\("tts-voice"\),
      rate: storage::local_get\("tts-rate"\)
        .and_then\(|s| s.parse::<f32>\(\).ok\(\)\)
        .unwrap_or\(1.0\),
      pitch: storage::local_get\("tts-pitch"\)
        .and_then\(|s| s.parse::<f32>\(\).ok\(\)\)
        .unwrap_or\(1.2\),
    }
  }
}

/// Initialize TTS module - called from lib.rs boot\(\)
pub fn init\(\) {
  load_state\(\);
  setup_toggle\(\);
  setup_settings_controls\(\);
  setup_voice_loading\(\);

  // Initial UI sync
  update_toggle_ui\(\);
  populate_voices\(\);
}

/// Main public API - speak the given text
pub fn speak\(text: &str\) {
  if !is_enabled\(\) {
    return;
  }

  stop\(\);

  let synth = match get_speech_synthesis\(\) {
    Some\(s\) => s,
    None => {
      web_sys::console::log_1\(&"SpeechSynthesis not available".into\(\)\);
      return;
    }
  };

  let utterance = match create_utterance\(text\) {
    Some\(u\) => u,
    None => {
      web_sys::console::log_1\(&"Failed to create utterance".into\(\)\);
      return;
    }
  };

  // Apply saved settings
  TTS_STATE.with\(|state| {
    let st = state.borrow\(\);

    // Set rate
    if let Ok\(_\) = Reflect::set\(&utterance, &"rate".into\(\), &st.rate.into\(\)\) {
      // Success
    }

    // Set pitch
    if let Ok\(_\) = Reflect::set\(&utterance, &"pitch".into\(\), &st.pitch.into\(\)\) {
      // Success
    }

    // Set voice if available
    if let Some\(voice_uri\) = &st.voice_uri {
      if let Some\(voice\) = find_voice\(voice_uri\) {
        if let Ok\(_\) = Reflect::set\(&utterance, &"voice".into\(\), &voice\) {
          // Success
        }
      }
    }
  }\);

  // Speak
  if let Some\(speak_fn\) = Reflect::get\(&synth, &"speak".into\(\)\).ok\(\)
    .and_then\(|f| f.dyn_into::<js_sys::Function>\(\).ok\(\)\) 
  {
    let _ = speak_fn.call1\(&synth, &utterance\);
  }
}

/// Cancel current speech
pub fn stop\(\) {
  if let Some\(synth\) = get_speech_synthesis\(\) {
    if let Some\(cancel_fn\) = Reflect::get\(&synth, &"cancel".into\(\)\).ok\(\)
      .and_then\(|f| f.dyn_into::<js_sys::Function>\(\).ok\(\)\)
    {
      let _ = cancel_fn.call0\(&synth\);
    }
  }
}

/// Check if TTS is enabled
pub fn is_enabled\(\) -> bool {
  TTS_STATE.with\(|state| state.borrow\(\).enabled\)
}

// ===== Internal helpers =====

fn load_state\(\) {
  TTS_STATE.with\(|state| {
    *state.borrow_mut\(\) = TtsState::default\(\);
  }\);
}

fn get_speech_synthesis\(\) -> Option<JsValue> {
  let window = dom::window\(\);
  Reflect::get\(&window, &"speechSynthesis".into\(\)\).ok\(\)
}

fn create_utterance\(text: &str\) -> Option<JsValue> {
  let window = dom::window\(\);
  let utterance_constructor = Reflect::get\(&window, &"SpeechSynthesisUtterance".into\(\)\).ok\(\)?;
  let utterance_constructor = utterance_constructor.dyn_into::<js_sys::Function>\(\).ok\(\)?;

  let args = Array::new\(\);
  args.push\(&text.into\(\)\);

  js_sys::Reflect::construct\(&utterance_constructor, &args\).ok\(\)
}

fn get_voices\(\) -> Option<Array> {
  let synth = get_speech_synthesis\(\)?;
  let get_voices_fn = Reflect::get\(&synth, &"getVoices".into\(\)\).ok\(\)?
    .dyn_into::<js_sys::Function>\(\).ok\(\)?;

  let voices = get_voices_fn.call0\(&synth\).ok\(\)?;
  voices.dyn_into::<Array>\(\).ok\(\)
}

fn find_voice\(voice_uri: &str\) -> Option<JsValue> {
  let voices = get_voices\(\)?;

  for i in 0..voices.length\(\) {
    if let Some\(voice\) = voices.get\(i\).as_ref\(\).into\(\) {
      if let Ok\(uri\) = Reflect::get\(&voice, &"voiceURI".into\(\)\) {
        if let Some\(uri_str\) = uri.as_string\(\) {
          if uri_str == voice_uri {
            return Some\(voice\);
          }
        }
      }
    }
  }

  None
}

fn setup_toggle\(\) {
  if let Some\(toggle\) = dom::query\("[data-voice-toggle]"\) {
    let cb = Closure::<dyn FnMut\(\)>::new\(move || {
      TTS_STATE.with\(|state| {
        let mut st = state.borrow_mut\(\);
        st.enabled = !st.enabled;
        storage::local_set\("tts-enabled", &st.enabled.to_string\(\)\);
      }\);
      update_toggle_ui\(\);
    }\);

    let _ = toggle.add_event_listener_with_callback\("click", cb.as_ref\(\).unchecked_ref\(\)\);
    cb.forget\(\);
  }
}

fn update_toggle_ui\(\) {
  if let Some\(toggle\) = dom::query\("[data-voice-toggle]"\) {
    let enabled = is_enabled\(\);
    dom::set_attr\(&toggle, "aria-pressed", if enabled { "true" } else { "false" }\);
    dom::set_text_el\(&toggle, if enabled { "Coach voice" } else { "Voice off" }\);
  }
}

fn setup_settings_controls\(\) {
  // Voice select dropdown
  if let Some\(select\) = dom::query\("[data-tts-voice-select]"\) {
    let cb = Closure::<dyn FnMut\(web_sys::Event\)>::new\(move |event: web_sys::Event| {
      if let Some\(select\) = event.target\(\).and_then\(|t| t.dyn_into::<web_sys::HtmlSelectElement>\(\).ok\(\)\) {
        let voice_uri = select.value\(\);
        TTS_STATE.with\(|state| {
          state.borrow_mut\(\).voice_uri = Some\(voice_uri.clone\(\)\);
        }\);
        storage::local_set\("tts-voice", &voice_uri\);
      }
    }\);

    let _ = select.add_event_listener_with_callback\("change", cb.as_ref\(\).unchecked_ref\(\)\);
    cb.forget\(\);
  }

  // Rate slider
  if let Some\(rate_slider\) = dom::query\("[data-tts-rate]"\) {
    let cb = Closure::<dyn FnMut\(web_sys::Event\)>::new\(move |event: web_sys::Event| {
      if let Some\(input\) = event.target\(\).and_then\(|t| t.dyn_into::<web_sys::HtmlInputElement>\(\).ok\(\)\) {
        let rate = input.value_as_number\(\) as f32;
        TTS_STATE.with\(|state| {
          state.borrow_mut\(\).rate = rate;
        }\);
        storage::local_set\("tts-rate", &rate.to_string\(\)\);
      }
    }\);

    let _ = rate_slider.add_event_listener_with_callback\("input", cb.as_ref\(\).unchecked_ref\(\)\);
    cb.forget\(\);

    // Set initial value
    TTS_STATE.with\(|state| {
      let rate = state.borrow\(\).rate;
      if let Ok\(input\) = rate_slider.dyn_into::<web_sys::HtmlInputElement>\(\) {
        input.set_value\(&rate.to_string\(\)\);
      }
    }\);
  }

  // Pitch slider
  if let Some\(pitch_slider\) = dom::query\("[data-tts-pitch]"\) {
    let cb = Closure::<dyn FnMut\(web_sys::Event\)>::new\(move |event: web_sys::Event| {
      if let Some\(input\) = event.target\(\).and_then\(|t| t.dyn_into::<web_sys::HtmlInputElement>\(\).ok\(\)\) {
        let pitch = input.value_as_number\(\) as f32;
        TTS_STATE.with\(|state| {
          state.borrow_mut\(\).pitch = pitch;
        }\);
        storage::local_set\("tts-pitch", &pitch.to_string\(\)\);
      }
    }\);

    let _ = pitch_slider.add_event_listener_with_callback\("input", cb.as_ref\(\).unchecked_ref\(\)\);
    cb.forget\(\);

    // Set initial value
    TTS_STATE.with\(|state| {
      let pitch = state.borrow\(\).pitch;
      if let Ok\(input\) = pitch_slider.dyn_into::<web_sys::HtmlInputElement>\(\) {
        input.set_value\(&pitch.to_string\(\)\);
      }
    }\);
  }
}

fn setup_voice_loading\(\) {
  // Safari/iOS loads voices asynchronously - listen for voiceschanged event
  if let Some\(synth\) = get_speech_synthesis\(\) {
    let cb = Closure::<dyn FnMut\(\)>::new\(move || {
      populate_voices\(\);
    }\);

    let _ = Reflect::get\(&synth, &"addEventListener".into\(\)\)
      .ok\(\)
      .and_then\(|f| f.dyn_into::<js_sys::Function>\(\).ok\(\)\)
      .and_then\(|add_listener| {
        add_listener.call2\(&synth, &"voiceschanged".into\(\), cb.as_ref\(\).unchecked_ref\(\)\).ok\(\)
      }\);

    cb.forget\(\);
  }
}

fn populate_voices\(\) {
  let select = match dom::query\("[data-tts-voice-select]"\) {
    Some\(s\) => s,
    None => return,
  };

  let select_el = match select.dyn_into::<web_sys::HtmlSelectElement>\(\) {
    Ok\(s\) => s,
    Err\(_\) => return,
  };

  // Clear existing options
  select_el.set_inner_html\(""\);

  let voices = match get_voices\(\) {
    Some\(v\) => v,
    None => return,
  };

  let saved_voice_uri = TTS_STATE.with\(|state| state.borrow\(\).voice_uri.clone\(\)\);

  // Filter to English voices only
  for i in 0..voices.length\(\) {
    if let Some\(voice\) = voices.get\(i\).as_ref\(\).into\(\) {
      let lang = Reflect::get\(&voice, &"lang".into\(\)\)
        .ok\(\)
        .and_then\(|l| l.as_string\(\)\)
        .unwrap_or_default\(\);

      if !lang.starts_with\("en"\) {
        continue;
      }

      let name = Reflect::get\(&voice, &"name".into\(\)\)
        .ok\(\)
        .and_then\(|n| n.as_string\(\)\)
        .unwrap_or_else\(|| "Unknown".to_string\(\)\);

      let voice_uri = Reflect::get\(&voice, &"voiceURI".into\(\)\)
        .ok\(\)
        .and_then\(|u| u.as_string\(\)\)
        .unwrap_or_default\(\);

      // Create option element
      let doc = dom::document\(\);
      if let Ok\(option\) = doc.create_element\("option"\) {
        option.set_text_content\(Some\(&name\)\);
        dom::set_attr\(&option, "value", &voice_uri\);

        // Pre-select if this matches saved voice
        if let Some\(ref saved_uri\) = saved_voice_uri {
          if saved_uri == &voice_uri {
            dom::set_attr\(&option, "selected", "selected"\);
          }
        } else if i == 0 {
          // Select first voice by default
          dom::set_attr\(&option, "selected", "selected"\);
          TTS_STATE.with\(|state| {
            state.borrow_mut\(\).voice_uri = Some\(voice_uri.clone\(\)\);
          }\);
          storage::local_set\("tts-voice", &voice_uri\);
        }

        let _ = select_el.append_child\(&option\);
      }
    }
  }
}
