fn now_ms\(\) -> f64 {
    js_sys::Date::now\(\)
}

fn random_pick\(options: &[&str]\) -> &str {
    let idx = \(js_sys::Math::random\(\) * options.len\(\) as f64\).floor\(\) as usize;
    options[idx % options.len\(\)]
}

fn hide_element\(selector: &str\) {
    if let Some\(el\) = dom::query\(selector\) {
        let _ = el.set_attribute\("hidden", ""\);
