fn check_streak_eligible\(\) -> bool {
    COACH.with\(|coach| {
        let state = coach.borrow\(\);
        let activities = &state.activities_done;

        // Minimum: warmup + 1 other activity
        let has_warmup = activities.contains\(&"warmup".to_string\(\)\);
        let other_count = activities.iter\(\).filter\(|a| *a != "warmup"\).count\(\);

        if has_warmup && other_count >= 1 {
            return true;
        }

        // OR any game with score >= 50 \(placeholder - would need actual game score check\)
        activities.contains\(&"game".to_string\(\)\)
    }\)
}

