    let mut init = CustomEventInit::new\(\);
    init.detail\(&wasm_bindgen::JsValue::from_str\(panel_name\)\);

    if let Ok\(event\) = CustomEvent::new_with_event_init_dict\("coach:navigate", &init\) {
