}

fn handle_activity_pick\(activity: &str\) {
    COACH.with\(|coach| {
        coach.borrow_mut\(\).activities_done.push\(activity.to_string\(\)\);
    }\);

    let \(message, panel\) = match activity {
        "warmup" => \(random_pick\(ACK_WARMUP\), "panel-tools"\),
        "piece" => \(random_pick\(ACK_PIECE\), "panel-map"\),
        "game" => \(random_pick\(ACK_GAME\), "panel-games"\),
        "tools" => \(random_pick\(ACK_TOOLS\), "panel-tools"\),
        "map" => \(random_pick\(ACK_MAP\), "panel-map"\),
        _ => \("Let's go!", "panel-home"\),
    };

