// ============================================================================
// Session End / Celebration
// ============================================================================

fn show_celebration\(state: &Rc<RefCell<AppState>>\) {
    let app = state.borrow\(\);
    let elapsed_ms = app.session_timer.elapsed;
    let minutes = \(elapsed_ms / 60000.0\).round\(\);

    let eligible = check_streak_eligible\(\);
    let streak_text = if eligible {
        "You earned a streak day! 🔥"
    } else {
        "Try warmup + another activity next time for streak credit!"
    };

    let message = format!\(
        "{} You practiced {:.0} minutes today. {}",
        random_pick\(CELEBRATION_MESSAGES\),
        minutes,
        streak_text
    \);

    show_message\(&message, CoachMood::Celebrate\);
    play_sfx\("celebrate"\);

    // Save session info
    storage::local_set\("coach_last_session_minutes", &format!\("{}", minutes\)\);

    COACH.with\(|coach| {
        coach.borrow_mut\(\).last_session_summary = Some\(message.clone\(\)\);
    }\);
}

// ============================================================================
// Timer Check \(for 20-minute nudge\)
// ============================================================================

fn check_nudge\(state: &Rc<RefCell<AppState>>\) {
    COACH.with\(|coach| {
        let mut coach_state = coach.borrow_mut\(\);
        if coach_state.nudge_shown {
            return;
        }

        let app = state.borrow\(\);
        let elapsed_ms = app.session_timer.elapsed;
        let minutes = elapsed_ms / 60000.0;

        if minutes >= 20.0 && app.session_timer.running {
            coach_state.nudge_shown = true;
            drop\(coach_state\); // Release borrow before showing UI
            show_nudge\(\);
        }
    }\);
}

// ============================================================================
// Session Panel Visibility Observer
// ============================================================================

fn setup_panel_observer\(state: Rc<RefCell<AppState>>\) {
    if let Some\(panel\) = dom::query\("#panel-session"\) {
        // Create an intersection observer to detect when panel becomes visible
        let callback = Closure::<dyn FnMut\(js_sys::Array\)>::new\(move |entries: js_sys::Array| {
            if let Some\(entry\) = entries.get\(0\).dyn_ref::<web_sys::IntersectionObserverEntry>\(\) {
                if entry.is_intersecting\(\) {
                    on_session_panel_visible\(\);
                }
            }
        }\);

        let options = web_sys::IntersectionObserverInit::new\(\);
        if let Ok\(observer\) = web_sys::IntersectionObserver::new_with_options\(
            callback.as_ref\(\).unchecked_ref\(\),
            &options,
        \) {
            observer.observe\(&panel\);
            callback.forget\(\);
        }
    }
}

fn on_session_panel_visible\(\) {
    COACH.with\(|coach| {
        let mut state = coach.borrow_mut\(\);
        if state.session_start_ms == 0.0 {
            state.session_start_ms = now_ms\(\);
            state.activities_done.clear\(\);
            state.nudge_shown = false;
            drop\(state\); // Release borrow before UI operations
            show_greeting\(\);
        }
    }\);
}

// ============================================================================
// Public Init Function
// ============================================================================

pub fn init\(state: Rc<RefCell<AppState>>\) {
    web_sys::console::log_1\(&"Coach module initializing".into\(\)\);

    // Setup panel visibility observer
    setup_panel_observer\(state.clone\(\)\);

    // Setup activity menu buttons
    for activity in &["warmup", "piece", "game", "tools", "map"] {
        let selector = format!\("[data-coach-pick='{}']", activity\);
        if let Some\(btn\) = dom::query\(&selector\) {
            let activity = activity.to_string\(\);
            let cb = Closure::<dyn FnMut\(Event\)>::new\(move |_: Event| {
                handle_activity_pick\(&activity\);
            }\);
            let _ = btn.add_event_listener_with_callback\("click", cb.as_ref\(\).unchecked_ref\(\)\);
            cb.forget\(\);
        }
    }

    // Setup nudge buttons
    if let Some\(btn\) = dom::query\("[data-coach-continue]"\) {
        let cb = Closure::<dyn FnMut\(Event\)>::new\(move |_: Event| {
            hide_nudge\(\);
        }\);
        let _ = btn.add_event_listener_with_callback\("click", cb.as_ref\(\).unchecked_ref\(\)\);
        cb.forget\(\);
    }

    if let Some\(btn\) = dom::query\("[data-coach-wrap-up]"\) {
        let state_clone = state.clone\(\);
        let cb = Closure::<dyn FnMut\(Event\)>::new\(move |_: Event| {
            hide_nudge\(\);
            show_celebration\(&state_clone\);
            // Trigger session finish via custom event
            let doc = dom::document\(\);
            if let Ok\(event\) = CustomEvent::new\("coach:finish-session"\) {
                let _ = doc.dispatch_event\(&event\);
            }
        }\);
        let _ = btn.add_event_listener_with_callback\("click", cb.as_ref\(\).unchecked_ref\(\)\);
        cb.forget\(\);
    }

    // Setup periodic nudge check \(every 30 seconds\)
    let state_clone = state.clone\(\);
    let cb = Closure::<dyn FnMut\(\)>::new\(move || {
        check_nudge\(&state_clone\);
    }\);
    let _ = dom::window\(\).set_interval_with_callback_and_timeout_and_arguments_0\(
        cb.as_ref\(\).unchecked_ref\(\),
        30000,
    \);
    cb.forget\(\);

    // Listen for session finish events from other modules
    let state_clone = state.clone\(\);
    let cb = Closure::<dyn FnMut\(Event\)>::new\(move |_: Event| {
        save_session_date\(\);
    }\);
    let doc = dom::document\(\);
    let _ = doc.add_event_listener_with_callback\("session:finished", cb.as_ref\(\).unchecked_ref\(\)\);
    cb.forget\(\);

    web_sys::console::log_1\(&"Coach module initialized".into\(\)\);
}
