    let _ = osc.stop_with_when\(start_time + duration\);
}

/// Play a note with slight vibrato effect
fn play_note_with_vibrato\(
    ctx: &AudioContext,
    freq: f64,
    duration: f64,
    start_offset: f64,
    volume: f32,
\) {
    let Ok\(osc\) = ctx.create_oscillator\(\) else { return };
    let Ok\(gain\) = ctx.create_gain\(\) else { return };
    let Ok\(vibrato_osc\) = ctx.create_oscillator\(\) else { return };
    let Ok\(vibrato_gain\) = ctx.create_gain\(\) else { return };

    let now = ctx.current_time\(\);
    let start_time = now + start_offset;

    // Main oscillator
    osc.set_type\(OscillatorType::Sine\);
    if let Ok\(freq_param\) = osc.frequency\(\) {
        let _ = freq_param.set_value_at_time\(freq, start_time\);
    }

    // Vibrato LFO \(5Hz, depth ~10Hz\)
    vibrato_osc.set_type\(OscillatorType::Sine\);
    if let Ok\(vibrato_freq\) = vibrato_osc.frequency\(\) {
        let _ = vibrato_freq.set_value_at_time\(5.0, start_time\);
    }
    if let Ok\(vibrato_gain_param\) = vibrato_gain.gain\(\) {
        let _ = vibrato_gain_param.set_value_at_time\(10.0, start_time\);
    }

    // Envelope
    if let Ok\(gain_param\) = gain.gain\(\) {
        let _ = gain_param.set_value_at_time\(0.0, start_time\);
        let _ = gain_param.linear_ramp_to_value_at_time\(volume, start_time + 0.02\);
        let _ = gain_param.linear_ramp_to_value_at_time\(0.0, start_time + duration\);
    }

    // Connect vibrato to main oscillator frequency
    let _ = vibrato_osc.connect_with_audio_node\(&vibrato_gain\);
    if let Ok\(freq_param\) = osc.frequency\(\) {
        let _ = vibrato_gain.connect_with_audio_param\(&freq_param\);
    }

    // Connect main signal path
    let _ = osc.connect_with_audio_node\(&gain\);
    let _ = gain.connect_with_audio_node\(&ctx.destination\(\)\);

    // Start both oscillators
    let _ = vibrato_osc.start_with_when\(start_time\);
    let _ = osc.start_with_when\(start_time\);
    let _ = vibrato_osc.stop_with_when\(start_time + duration\);
    let _ = osc.stop_with_when\(start_time + duration\);
}
