#![allow\(dead_code\)]

//! "Note Catch" ear training game for Emerson's Practice World
//!
//! Panda plays random notes via Web Audio oscillator, Emerson identifies
//! the violin string \(G, D, A, E\) by tapping buttons. Difficulty scales
//! based on current piece: open strings -> first position -> intervals.

use std::cell::RefCell;
use std::thread_local;
use wasm_bindgen::closure::Closure;
use wasm_bindgen::JsCast;
use wasm_bindgen::JsValue;
use web_sys::{AudioContext, CustomEvent, CustomEventInit, Event, GainNode, OscillatorNode, OscillatorType};

use crate::dom;
use crate::onboarding;
use crate::sfx;

thread_local! {
    static STATE: RefCell<EarTrainingState> = RefCell::new\(EarTrainingState::default\(\)\);
}

struct EarTrainingState {
    active: bool,
    round: usize,
    total_rounds: usize,
    correct: usize,
    current_midi: u8,
    audio_ctx: Option<AudioContext>,
    waiting_answer: bool,
    difficulty: u8,
}

impl Default for EarTrainingState {
    fn default\(\) -> Self {
        Self {
            active: false,
            round: 0,
            total_rounds: 10,
            correct: 0,
            current_midi: 0,
            audio_ctx: None,
            waiting_answer: false,
            difficulty: 1,
        }
    }
}

/// Note pools by difficulty level
const DIFFICULTY_1_NOTES: &[u8] = &[55, 62, 69, 76]; // Open strings: G3, D4, A4, E5
const DIFFICULTY_2_NOTES: &[u8] = &[55, 57, 59, 60, 62, 64, 66, 67, 69, 71, 73, 74, 76, 78]; // First position

pub fn init\(\) {
    bind_start_button\(\);
    bind_string_buttons\(\);
}

fn bind_start_button\(\) {
    if let Some\(btn\) = dom::query\("[data-ear-start]"\) {
        let cb = Closure::<dyn FnMut\(Event\)>::new\(move |_e: Event| {
            start_game\(\);
        }\);
        let _ = btn.add_event_listener_with_callback\("click", cb.as_ref\(\).unchecked_ref\(\)\);
        cb.forget\(\);
    }
}

fn bind_string_buttons\(\) {
    for string_name in &["G", "D", "A", "E"] {
        let selector = format!\("[data-ear-string-{}]", string_name\);
        if let Some\(btn\) = dom::query\(&selector\) {
            let name = string_name.to_string\(\);
            let cb = Closure::<dyn FnMut\(Event\)>::new\(move |_e: Event| {
                check_answer\(&name\);
            }\);
            let _ = btn.add_event_listener_with_callback\("click", cb.as_ref\(\).unchecked_ref\(\)\);
            cb.forget\(\);
        }
    }
}

fn start_game\(\) {
    STATE.with\(|s| {
        let mut st = s.borrow_mut\(\);
        st.active = true;
        st.round = 0;
        st.correct = 0;
        st.waiting_answer = false;

        // Determine difficulty from current piece
        let piece_id = onboarding::current_piece_id\(\);
        st.difficulty = if piece_id.is_empty\(\) || piece_id.starts_with\("twinkle"\) {
            1
        } else {
            2
        };

        // Ensure AudioContext exists
        if st.audio_ctx.is_none\(\) {
            if let Ok\(ctx\) = AudioContext::new\(\) {
                st.audio_ctx = Some\(ctx\);
            }
        }
    }\);

    update_ui\(\);
    play_random_note\(\);
}

fn play_random_note\(\) {
    STATE.with\(|s| {
        let mut st = s.borrow_mut\(\);
        if !st.active || st.round >= st.total_rounds {
            return;
        }

        let notes = if st.difficulty == 1 {
            DIFFICULTY_1_NOTES
        } else {
            DIFFICULTY_2_NOTES
        };

        let idx = \(js_sys::Math::random\(\) * notes.len\(\) as f64\).floor\(\) as usize;
        st.current_midi = notes[idx.min\(notes.len\(\) - 1\)];
        st.waiting_answer = true;

        play_midi_note\(st.current_midi, &st.audio_ctx\);
    }\);

    update_ui\(\);
}

fn play_midi_note\(midi: u8, ctx_opt: &Option<AudioContext>\) {
    let Some\(ctx\) = ctx_opt else { return };

    // MIDI to frequency: f = 440 * 2^\(\(midi - 69\) / 12\)
    let freq = 440.0 * 2.0_f64.powf\(\(midi as f64 - 69.0\) / 12.0\);

    let Ok\(osc\) = ctx.create_oscillator\(\) else { return };
    let Ok\(gain\) = ctx.create_gain\(\) else { return };

    osc.set_type\(OscillatorType::Triangle\);
    let _ = osc.frequency\(\).set_value\(freq as f32\);

    let now = ctx.current_time\(\);
    let _ = gain.gain\(\).set_value_at_time\(0.0, now\);
    let _ = gain.gain\(\).linear_ramp_to_value_at_time\(0.2, now + 0.02\); // Attack
    let _ = gain.gain\(\).set_value_at_time\(0.2, now + 0.62\); // Sustain
    let _ = gain.gain\(\).linear_ramp_to_value_at_time\(0.0, now + 0.82\); // Release

    let _ = osc.connect_with_audio_node\(&gain\);
    let _ = gain.connect_with_audio_node\(&ctx.destination\(\)\);

    let _ = osc.start\(\);
    let _ = osc.stop_with_when\(now + 0.82\);
}

fn check_answer\(string: &str\) {
    STATE.with\(|s| {
        let mut st = s.borrow_mut\(\);
        if !st.waiting_answer {
            return;
        }

        st.waiting_answer = false;

        // Determine correct string from MIDI note
        let correct_string = if st.current_midi >= 76 {
            "E"
        } else if st.current_midi >= 69 {
            "A"
        } else if st.current_midi >= 62 {
            "D"
        } else {
            "G"
        };

        if string == correct_string {
            sfx::play\("tap"\);
            st.correct += 1;
            flash_feedback\(true\);
        } else {
            sfx::play\("chirp"\);
            flash_feedback\(false\);
            // Replay the note
            play_midi_note\(st.current_midi, &st.audio_ctx\);
            show_correct_answer\(correct_string\);
        }

        st.round += 1;

        if st.round >= st.total_rounds {
            end_game\(\);
        } else {
            // Delay before next note
            let window = dom::window\(\);
            let cb = Closure::<dyn FnMut\(\)>::new\(move || {
                play_random_note\(\);
            }\);
            let _ = window.set_timeout_with_callback_and_timeout_and_arguments_0\(
                cb.as_ref\(\).unchecked_ref\(\),
                1200,
            \);
            cb.forget\(\);
        }
    }\);

    update_ui\(\);
}

fn flash_feedback\(correct: bool\) {
    if let Some\(canvas\) = dom::query\("[data-ear-canvas]"\) {
        let class = if correct { "flash-green" } else { "flash-red" };
        let _ = canvas.class_list\(\).add_1\(class\);

        let window = dom::window\(\);
        let cb = Closure::<dyn FnMut\(\)>::new\(move || {
            if let Some\(canvas\) = dom::query\("[data-ear-canvas]"\) {
                let _ = canvas.class_list\(\).remove_1\(class\);
            }
        }\);
        let _ = window.set_timeout_with_callback_and_timeout_and_arguments_0\(
            cb.as_ref\(\).unchecked_ref\(\),
            300,
        \);
        cb.forget\(\);
    }
}

fn show_correct_answer\(string: &str\) {
    let msg = format!\("That was the {} string!", string\);
    dom::set_text\("[data-ear-status]", &msg\);
}

fn end_game\(\) {
    STATE.with\(|s| {
        let mut st = s.borrow_mut\(\);
        st.active = false;

        let score_pct = \(st.correct as f64 / st.total_rounds as f64 * 100.0\).round\(\) as i32;
        let msg = format!\("Game over! You got {}/{} \({}%\)", st.correct, st.total_rounds, score_pct\);
        dom::toast\(&msg\);

        // Dispatch completion event
        let doc = dom::document\(\);
        let mut init = CustomEventInit::new\(\);
        init.detail\(&JsValue::from_f64\(score_pct as f64\)\);
        if let Ok\(evt\) = CustomEvent::new_with_event_init_dict\("ear-training:complete", &init\) {
            let _ = doc.dispatch_event\(&evt\);
        }
    }\);

    update_ui\(\);
}

fn update_ui\(\) {
    STATE.with\(|s| {
        let st = s.borrow\(\);

        dom::set_text\("[data-ear-round]", &format!\("{}/{}", st.round + 1, st.total_rounds\)\);
        dom::set_text\("[data-ear-score]", &format!\("{} correct", st.correct\)\);

        if st.waiting_answer {
            dom::set_text\("[data-ear-status]", "Listen and tap the correct string!"\);
        } else if st.active {
            dom::set_text\("[data-ear-status]", "Get ready for the next note..."\);
        } else {
            dom::set_text\("[data-ear-status]", "Tap Start to begin!"\);
        }
    }\);

    draw\(\);
}

fn draw\(\) {
    let Some\(canvas_el\) = dom::query\("[data-ear-canvas]"\) else { return };
    let Ok\(canvas\) = canvas_el.dyn_into::<web_sys::HtmlCanvasElement>\(\) else { return };
    let Ok\(ctx\) = canvas.get_context\("2d"\) else { return };
    let Some\(ctx\) = ctx else { return };
    let Ok\(ctx\) = ctx.dyn_into::<web_sys::CanvasRenderingContext2d>\(\) else { return };

    let w = canvas.width\(\) as f64;
    let h = canvas.height\(\) as f64;

    ctx.clear_rect\(0.0, 0.0, w, h\);

    // Draw 4 string zones: G \(brown\), D \(orange\), A \(yellow\), E \(green\)
    let zone_h = h / 4.0;
    let colors = ["#8B4513", "#FF8C00", "#FFD700", "#32CD32"];
    let labels = ["G", "D", "A", "E"];

    for \(i, \(&color, &label\)\) in colors.iter\(\).zip\(labels.iter\(\)\).enumerate\(\) {
        let y = i as f64 * zone_h;
        ctx.set_fill_style\(&JsValue::from_str\(color\)\);
        ctx.fill_rect\(0.0, y, w, zone_h\);

        ctx.set_fill_style\(&JsValue::from_str\("#FFF"\)\);
        ctx.set_font\("24px system-ui"\);
        ctx.set_text_baseline\("middle"\);
        let _ = ctx.fill_text\(label, w - 40.0, y + zone_h / 2.0\);
    }

    // Draw progress bar
    STATE.with\(|s| {
        let st = s.borrow\(\);
        if st.total_rounds > 0 {
            let progress = st.round as f64 / st.total_rounds as f64;
            ctx.set_fill_style\(&JsValue::from_str\("rgba\(255,255,255,0.8\)"\)\);
            ctx.fill_rect\(0.0, 0.0, w * progress, 8.0\);
        }
    }\);
}
