#![allow\(dead_code\)]

//! Scale Sprint - Violin scale warm-up game for young students
//!
//! Race up and down scales against a timer. Panda runs alongside matching accuracy.
//! Uses real-time pitch detection from microphone input to track progress.

use std::cell::RefCell;
use wasm_bindgen::closure::Closure;
use wasm_bindgen::JsCast;
use wasm_bindgen::JsValue;
use web_sys::{
    AudioContext, CanvasRenderingContext2d, Event, HtmlCanvasElement, MediaStream, MediaStreamTrack,
};

use crate::dom;
use crate::sfx;
use crate::storage;

// Scale data \(MIDI note numbers\)
const G_MAJOR: &[u8] = &[55, 57, 59, 60, 62, 64, 66, 67]; // G3 to G4
const D_MAJOR: &[u8] = &[62, 64, 66, 67, 69, 71, 73, 74]; // D4 to D5
const A_MAJOR: &[u8] = &[69, 71, 73, 74, 76, 78]; // A4 to F#5

thread_local! {
    static STATE: RefCell<ScaleGameState> = RefCell::new\(ScaleGameState::default\(\)\);
}

struct ScaleGameState {
    active: bool,
    scale: &'static [u8],
    scale_name: String,
    note_index: usize,
    going_up: bool,
    audio_ctx: Option<AudioContext>,
    mic_analyser: Option<web_sys::AnalyserNode>,
    mic_stream: Option<MediaStream>,
    raf_id: Option<i32>,
    start_ms: f64,
    elapsed_ms: f64,
    notes_hit: usize,
    best_time_ms: f64,
}

impl Default for ScaleGameState {
    fn default\(\) -> Self {
        let best = storage::local_get\("scale-sprint:best"\)
            .and_then\(|s| s.parse::<f64>\(\).ok\(\)\)
            .unwrap_or\(0.0\);
        Self {
            active: false,
            scale: G_MAJOR,
            scale_name: "G Major".to_string\(\),
            note_index: 0,
            going_up: true,
            audio_ctx: None,
            mic_analyser: None,
            mic_stream: None,
            raf_id: None,
            start_ms: 0.0,
            elapsed_ms: 0.0,
            notes_hit: 0,
            best_time_ms: best,
        }
    }
}

/// Initialize Scale Sprint game
pub fn init\(\) {
    // Start button
    if let Some\(start_btn\) = dom::query\("[data-scale-start]"\) {
        let cb = Closure::<dyn FnMut\(Event\)>::new\(move |_event: Event| {
            start_game\(\);
        }\);
        let _ = start_btn.add_event_listener_with_callback\("click", cb.as_ref\(\).unchecked_ref\(\)\);
        cb.forget\(\);
    }

    // Scale selection buttons
    bind_scale_button\("[data-scale-g]", G_MAJOR, "G Major"\);
    bind_scale_button\("[data-scale-d]", D_MAJOR, "D Major"\);
    bind_scale_button\("[data-scale-a]", A_MAJOR, "A Major"\);

    // Initial render
    render_canvas\(\);
}

fn bind_scale_button\(selector: &str, scale: &'static [u8], name: &str\) {
    if let Some\(btn\) = dom::query\(selector\) {
        let scale_copy = scale;
        let name_str = name.to_string\(\);
        let cb = Closure::<dyn FnMut\(Event\)>::new\(move |_event: Event| {
            STATE.with\(|state| {
                let mut s = state.borrow_mut\(\);
                s.scale = scale_copy;
                s.scale_name = name_str.clone\(\);
            }\);
            dom::toast\(&format!\("Selected {}", name_str\)\);
            render_canvas\(\);
        }\);
        let _ = btn.add_event_listener_with_callback\("click", cb.as_ref\(\).unchecked_ref\(\)\);
        cb.forget\(\);
    }
}

fn start_game\(\) {
    let already_active = STATE.with\(|state| state.borrow\(\).active\);
    if already_active {
        stop_game\(\);
        return;
    }

    STATE.with\(|state| {
        let mut s = state.borrow_mut\(\);
        s.active = true;
        s.note_index = 0;
        s.going_up = true;
        s.start_ms = dom::window\(\).performance\(\).unwrap\(\).now\(\);
        s.elapsed_ms = 0.0;
        s.notes_hit = 0;
    }\);

    dom::set_text\("[data-scale-status]", "Starting..."\);

    let window = dom::window\(\);
    let navigator = window.navigator\(\);
    let media_devices = match navigator.media_devices\(\) {
        Ok\(dev\) => dev,
        Err\(_\) => {
            dom::toast\("Microphone unavailable"\);
            STATE.with\(|state| state.borrow_mut\(\).active = false\);
            return;
        }
    };

    let constraints = web_sys::MediaStreamConstraints::new\(\);
    constraints.set_audio\(&JsValue::TRUE\);
    let stream_promise = match media_devices.get_user_media_with_constraints\(&constraints\) {
        Ok\(p\) => p,
        Err\(_\) => {
            dom::toast\("Cannot access microphone"\);
            STATE.with\(|state| state.borrow_mut\(\).active = false\);
            return;
        }
    };

    wasm_bindgen_futures::spawn_local\(async move {
        let stream = match wasm_bindgen_futures::JsFuture::from\(stream_promise\).await {
            Ok\(val\) => val.dyn_into::<MediaStream>\(\).unwrap\(\),
            Err\(_\) => {
                dom::toast\("Microphone blocked"\);
                STATE.with\(|state| state.borrow_mut\(\).active = false\);
                return;
            }
        };

        let audio_ctx = match AudioContext::new\(\) {
            Ok\(ctx\) => ctx,
            Err\(_\) => {
                dom::toast\("Audio context failed"\);
                STATE.with\(|state| state.borrow_mut\(\).active = false\);
                return;
            }
        };
        let _ = audio_ctx.resume\(\);
        let source = audio_ctx.create_media_stream_source\(&stream\).unwrap\(\);
        let analyser = audio_ctx.create_analyser\(\).unwrap\(\);
        analyser.set_fft_size\(2048\);
        source.connect_with_audio_node\(&analyser\).ok\(\);

        STATE.with\(|state| {
            let mut s = state.borrow_mut\(\);
            s.audio_ctx = Some\(audio_ctx\);
            s.mic_analyser = Some\(analyser\);
            s.mic_stream = Some\(stream\);
        }\);

        dom::set_text\("[data-scale-status]", "Play your scale!"\);
        sfx::play\("chirp"\);

        // Start detection loop
        let cb = Closure::<dyn FnMut\(\)>::new\(move || {
            detection_loop\(\);
        }\);
        let id = dom::window\(\)
            .request_animation_frame\(cb.as_ref\(\).unchecked_ref\(\)\)
            .unwrap_or\(0\);
        STATE.with\(|state| state.borrow_mut\(\).raf_id = Some\(id\)\);
        cb.forget\(\);
    }\);
}

fn stop_game\(\) {
    STATE.with\(|state| {
        let mut s = state.borrow_mut\(\);
        if !s.active {
            return;
        }
        s.active = false;

        if let Some\(id\) = s.raf_id.take\(\) {
            let _ = dom::window\(\).cancel_animation_frame\(id\);
        }

        if let Some\(stream\) = s.mic_stream.take\(\) {
            let tracks = stream.get_tracks\(\);
            for idx in 0..tracks.length\(\) {
                if let Ok\(track\) = tracks.get\(idx\).dyn_into::<MediaStreamTrack>\(\) {
                    track.stop\(\);
                }
            }
        }

        if let Some\(ctx\) = s.audio_ctx.take\(\) {
            let _ = ctx.close\(\);
        }

        s.mic_analyser = None;
    }\);

    dom::set_text\("[data-scale-status]", "Stopped"\);
    render_canvas\(\);
}

fn detection_loop\(\) {
    let is_active = STATE.with\(|state| state.borrow\(\).active\);
    if !is_active {
        return;
    }

    let analyser = STATE.with\(|state| state.borrow\(\).mic_analyser.clone\(\)\);
    let Some\(analyser\) = analyser else {
        return;
    };

    let mut buffer = vec![0.0f32; analyser.fft_size\(\) as usize];
    analyser.get_float_time_domain_data\(&mut buffer\);

    if let Some\(freq\) = auto_correlate\(&buffer, analyser.context\(\).sample_rate\(\) as f64\) {
        check_note_match\(freq\);
    }

    // Update timer
    let now = dom::window\(\).performance\(\).unwrap\(\).now\(\);
    let elapsed = STATE.with\(|state| {
        let mut s = state.borrow_mut\(\);
        s.elapsed_ms = now - s.start_ms;
        s.elapsed_ms
    }\);

    dom::set_text\(
        "[data-scale-timer]",
        &format!\("{:.1}s", elapsed / 1000.0\),
    \);

    render_canvas\(\);

    // Continue loop
    let cb = Closure::<dyn FnMut\(\)>::new\(move || {
        detection_loop\(\);
    }\);
    let id = dom::window\(\)
        .request_animation_frame\(cb.as_ref\(\).unchecked_ref\(\)\)
        .unwrap_or\(0\);
    STATE.with\(|state| state.borrow_mut\(\).raf_id = Some\(id\)\);
    cb.forget\(\);
}

fn check_note_match\(freq: f64\) {
    let \(target_midi, should_advance\) = STATE.with\(|state| {
        let s = state.borrow\(\);
        let idx = s.note_index;
        let midi = if s.going_up {
            s.scale[idx]
        } else {
            s.scale[s.scale.len\(\) - 1 - idx]
        };
        let needs_more = idx < s.scale.len\(\) - 1 || !s.going_up;
        \(midi, needs_more\)
    }\);

    let target_freq = midi_to_freq\(target_midi\);
    let cents = 1200.0 * \(freq / target_freq\).log2\(\);

    // Within 50 cents = good enough for a kid!
    if cents.abs\(\) <= 50.0 {
        sfx::play\("tap"\);

        STATE.with\(|state| {
            let mut s = state.borrow_mut\(\);
            s.notes_hit += 1;

            if s.going_up {
                if s.note_index < s.scale.len\(\) - 1 {
                    s.note_index += 1;
                } else {
                    // Reached top, start descending
                    s.going_up = false;
                    s.note_index = 0;
                    sfx::play\("star"\);
                }
            } else {
                if s.note_index < s.scale.len\(\) - 1 {
                    s.note_index += 1;
                } else {
                    // Completed!
                    complete_game\(\);
                }
            }
        }\);
    }
}

fn complete_game\(\) {
    let \(elapsed, best\) = STATE.with\(|state| {
        let s = state.borrow\(\);
        \(s.elapsed_ms, s.best_time_ms\)
    }\);

    stop_game\(\);
    sfx::play\("celebrate"\);

    let is_new_best = best == 0.0 || elapsed < best;
    if is_new_best {
        storage::local_set\("scale-sprint:best", &format!\("{}", elapsed\)\);
        STATE.with\(|state| state.borrow_mut\(\).best_time_ms = elapsed\);
        dom::toast\(&format!\(
            "New best! {:.1}s",
            elapsed / 1000.0
        \)\);
    } else {
        dom::toast\(&format!\(
            "Complete! {:.1}s \(best: {:.1}s\)",
            elapsed / 1000.0,
            best / 1000.0
        \)\);
    }

    // Dispatch custom event
    let event = web_sys::CustomEvent::new\("scale-sprint:complete"\).unwrap\(\);
    let _ = dom::document\(\).dispatch_event\(&event\);
}

fn render_canvas\(\) {
    let canvas = match dom::query\("[data-scale-canvas]"\) {
        Some\(el\) => el.dyn_into::<HtmlCanvasElement>\(\).ok\(\),
        None => None,
    };
    let Some\(canvas\) = canvas else { return };

    let ctx = match canvas.get_context\("2d"\) {
        Ok\(Some\(c\)\) => c.dyn_into::<CanvasRenderingContext2d>\(\).ok\(\),
        _ => None,
    };
    let Some\(ctx\) = ctx else { return };

    let width = canvas.width\(\) as f64;
    let height = canvas.height\(\) as f64;

    // Clear
    ctx.set_fill_style\(&"#f0f0f0".into\(\)\);
    ctx.fill_rect\(0.0, 0.0, width, height\);

    STATE.with\(|state| {
        let s = state.borrow\(\);
        let scale_len = s.scale.len\(\);
        let total_steps = scale_len * 2 - 1; // up and down \(share top note\)
        let step_width = width / \(total_steps as f64 + 1.0\);

        // Draw stepping stones
        for i in 0..total_steps {
            let x = \(i + 1\) as f64 * step_width;
            let y = height / 2.0;

            let current_step = if s.going_up {
                s.note_index
            } else {
                scale_len + s.note_index
            };

            let is_completed = i < current_step || \(!s.active && i < total_steps\);
            let is_current = i == current_step && s.active;

            ctx.set_fill_style\(&if is_completed {
                "#4caf50".into\(\)
            } else if is_current {
                "#ff9800".into\(\)
            } else {
                "#e0e0e0".into\(\)
            }\);

            ctx.begin_path\(\);
            ctx.arc\(x, y, 20.0, 0.0, std::f64::consts::PI * 2.0\).ok\(\);
            ctx.fill\(\);

            // Note label
            let note_idx = if i < scale_len {
                i
            } else {
                scale_len * 2 - i - 1
            };
            let note = note_name\(s.scale[note_idx]\);
            ctx.set_fill_style\(&"#333".into\(\)\);
            ctx.set_font\("12px sans-serif"\);
            ctx.fill_text\(note, x - 10.0, y + 40.0\).ok\(\);
        }

        // Draw panda at current position
        if s.active {
            let current_step = if s.going_up {
                s.note_index
            } else {
                scale_len + s.note_index
            };
            let panda_x = \(current_step + 1\) as f64 * step_width;
            let panda_y = height / 2.0 - 50.0;

            ctx.set_fill_style\(&"#333".into\(\)\);
            ctx.set_font\("32px sans-serif"\);
            ctx.fill_text\("🐼", panda_x - 16.0, panda_y\).ok\(\);
        }
    }\);
}

// Pitch detection \(autocorrelation\)
fn auto_correlate\(buffer: &[f32], sample_rate: f64\) -> Option<f64> {
    let size = buffer.len\(\);
    let mut rms = 0.0;
    for val in buffer {
        rms += \(*val as f64\) * \(*val as f64\);
    }
    rms = \(rms / size as f64\).sqrt\(\);
    if rms < 0.01 {
        return None;
    }

    let mut r1 = 0;
    let mut r2 = size - 1;
    let threshold = 0.2;
    while r1 < size / 2 && buffer[r1].abs\(\) < threshold {
        r1 += 1;
    }
    while r2 > size / 2 && buffer[r2].abs\(\) < threshold {
        r2 -= 1;
    }

    let trimmed = &buffer[r1..r2];
    let trimmed_size = trimmed.len\(\);
    let mut c = vec![0.0f64; trimmed_size];
    for i in 0..trimmed_size {
        for j in 0..\(trimmed_size - i\) {
            c[i] += \(trimmed[j] as f64\) * \(trimmed[j + i] as f64\);
        }
    }
    let mut d = 0;
    while d + 1 < trimmed_size && c[d] > c[d + 1] {
        d += 1;
    }
    let mut max_value = -1.0;
    let mut max_index = -1;
    for i in d..trimmed_size {
        if c[i] > max_value {
            max_value = c[i];
            max_index = i as i32;
        }
    }
    if max_index <= 0 {
        return None;
    }
    Some\(sample_rate / max_index as f64\)
}

fn midi_to_freq\(midi: u8\) -> f64 {
    440.0 * 2.0_f64.powf\(\(midi as f64 - 69.0\) / 12.0\)
}

fn note_name\(midi: u8\) -> &'static str {
    let notes = [
        "C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B",
    ];
    notes[\(midi % 12\) as usize]
}
